   270	async function runCommand(root: string, command: CommandSpec): Promise<CommandResult> {
   271	  return new Promise((resolve) => {
   272	    const startedAt = Date.now()
   273	    let stdout = ""
   274	    let stderr = ""
   275	    let settled = false
   276	
   277	    let child
   278	    try {
   279	      child = spawn(command.argv[0], command.argv.slice(1), {
   280	        cwd: root,
   281	        env: process.env,
   282	        stdio: ["ignore", "pipe", "pipe"],
   283	      })
   284	    } catch (error) {
   285	      resolve({
   286	        ...command,
   287	        exit_code: -1,
   288	        duration_ms: Date.now() - startedAt,
   289	        stdout: "",
   290	        stderr: String(error),
   291	      })
   292	      return
   293	    }
   294	
   295	    child.stdout.on("data", (chunk) => {
   296	      stdout += chunk.toString()
   297	    })
   298	    child.stderr.on("data", (chunk) => {
   299	      stderr += chunk.toString()
   300	    })
   301	    child.on("error", (error) => {
   302	      if (settled) return
   303	      settled = true
   304	      const missingExecutable = typeof error === "object" && error && "code" in error && (error as { code?: string }).code === "ENOENT"
   305	        ? command.argv[0]
