   307	      resolve({
   308	        ...command,
   309	        exit_code: -1,
   310	        duration_ms: Date.now() - startedAt,
   311	        stdout,
   312	        stderr: `${stderr}\n${String(error)}`.trim(),
   313	        missing_executable: missingExecutable,
   314	      })
   315	    })
   316	    child.on("close", (code) => {
   317	      if (settled) return
   318	      settled = true
   319	      resolve({
   320	        ...command,
   321	        exit_code: code ?? -1,
   322	        duration_ms: Date.now() - startedAt,
   323	        stdout,
   324	        stderr,
   325	      })
   326	    })
   327	  })
   328	}
