    await saveArtifactRegistry(registry)

    return JSON.stringify(
      {
        ticket_id: ticket.id,
        artifact_count: ticket.artifacts.length,
        registry_count: registry.artifacts.length,
        latest_artifact: ticket.artifacts[ticket.artifacts.length - 1],
      },
      null,
      2,
    )
  },
})
